<link rel="stylesheet" href="/css/simple_page.css">

<style>
.image-container {
      display: flex; /* 使用 Flexbox 布局 */
      justify-content: center; /* 水平居中 */
      align-items: center; /* 垂直居中（适用于内容） */
      gap: 10px; /* 两张图片之间的间距 */
      margin-top: 20px;
    }
    .image-wrapper {
      display: flex;
      flex-direction: column; /* 垂直布局 */
      align-items: center; /* 内容居中 */
    }
    .image-wrapper img {
      width: 150px; /* 图片宽度，稍微小一些 */
      height: auto;
      border: 1px solid #ccc;
      box-shadow: 2px 2px 5px rgba(0, 0, 0, 0.2);
    }
    .image-wrapper p {
      margin: 5px 0; /* 图片文字的上、下间距 */
      font-size: 14px;
      color: #555;
    }
  </style>

<body>
  <meta charset="utf-8"/>
  <title>404 Page</title>
  <div class="content-wrapper">
    <section class="wrapper bg-light">
      <div class="container pt-12 pt-md-14 pb-14 pb-md-16">
        <p class="h1" >404
        </p>
        <div class="row">
          <div class="col-lg-9 col-xl-8 mx-auto">
            <figure class="mb-10">
              <img src="/image/404.gif" alt="" id="img404" />
            </figure>
          </div>
          <!-- /column -->
          <div class="col-lg-8 col-xl-7 col-xxl-6 mx-auto text-center">
            <p class="h3" id="mainText404">(⊙o⊙)… 页面不存在</p>
            <p class="text_align" id="subText404">试一下搜索框，有可能只是链接替换了
            </p>
            <a onclick="like()" class="button" style="color: #FFFFFF; background-color: #c91a77">奖励博主</a>
            <a href="/" class="button" style="color: #FFFFFF;">返回首页</a>
            <a href="/pages/about/#post-comment" class="button" style="color: #FFFFFF; background-color: #727272">鞭笞博主</a>
          </div>
          <!-- /column -->
        </div>
        <!-- /.row -->
      </div>
        <!-- 动态展示图片的容器 -->
        <div id="imageContainer" class="image-container"></div>
      <!-- /.container -->
    </section>
    <!-- /section -->
  </div>

  <!-- /.content-wrapper -->  
<script>

function like(){
    changeImage();
    showImages();
}

// 按钮点击事件：更换图片 src
function changeImage() {
  const image = document.getElementById('img404');
  image.src = "/image/like.gif"; // 新的图片地址
}

// 点击按钮后展示图片
    function showImages() {
      const container = document.getElementById('imageContainer');

    // 检查是否已经加载了图片
      if (container.children.length > 0) {
        return; // 如果容器中已经有图片，直接退出，不重复加载
      }

        const mainText = document.getElementById('mainText404');
        mainText.textContent = "(●ˇ∀ˇ●) 喵喵喵~";
        const subText = document.getElementById('subText404');
        subText.textContent = "感谢你对我创作内容的肯定！";

      // 清空容器，防止重复添加
      container.innerHTML = '';

      // 创建第一张图片及其文字描述
      const wrapper1 = document.createElement('div');
      wrapper1.className = 'image-wrapper';

      const caption1 = document.createElement('p');
      caption1.textContent = '请我吃冻干(微信)';
      const img1 = document.createElement('img');
      img1.src = '/image/wx.png';
      img1.alt = '微信';

      wrapper1.appendChild(caption1);
      wrapper1.appendChild(img1);

      // 创建第二张图片及其文字描述
      const wrapper2 = document.createElement('div');
      wrapper2.className = 'image-wrapper';

      const caption2 = document.createElement('p');
      caption2.textContent = '给我添猫粮(支付宝)';
      const img2 = document.createElement('img');
      img2.src = '/image/zfb.png';
      img2.alt = '支付宝';

      wrapper2.appendChild(caption2);
      wrapper2.appendChild(img2);

      // 将图片及文字添加到容器中
      container.appendChild(wrapper1);
      container.appendChild(wrapper2);
    }
</script>
</body>
